import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(-1);
    const [isPlaying, setIsPlaying] = useState(false);
    const audioRef = useRef(null);

    const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/songs');
                setSongs(res.data);
            } catch (err) { console.error(err); }
        };
        fetchSongs();
    }, []);

    const playSong = (index) => {
        setCurrentIndex(index);
        setIsPlaying(true);
    };

    const nextSong = () => {
        if (songs.length === 0) return;
        setCurrentIndex((prev) => (prev + 1) % songs.length);
    };

    const prevSong = () => {
        if (songs.length === 0) return;
        setCurrentIndex((prev) => (prev - 1 + songs.length) % songs.length);
    };

    const togglePlay = () => {
        if (isPlaying) audioRef.current.pause();
        else audioRef.current.play();
        setIsPlaying(!isPlaying);
    };

    return (
        <div style={{ padding: '40px 20px', maxWidth: '1000px', margin: '0 auto', paddingBottom: '120px' }}>
            <h2 style={{ textAlign: 'center', marginBottom: '40px', letterSpacing: '1px' }}>DANH SÁCH BÀI HÁT</h2>
            
            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                {songs.map((song, index) => (
                    <div key={song._id} style={{
                        display: 'flex', 
                        alignItems: 'center', 
                        padding: '15px 25px', 
                        border: '1px solid #f0f0f0', 
                        borderRadius: '15px',
                        background: currentIndex === index ? '#f8f9ff' : '#fff',
                        boxShadow: '0 4px 6px rgba(0,0,0,0.02)',
                        justifyContent: 'space-between'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center' }}>
                            <img src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/60'} 
                                 style={{ width: '60px', height: '60px', marginRight: '20px', borderRadius: '10px', objectFit: 'cover' }} alt="thumb" />
                            <div>
                                <div style={{ fontWeight: 'bold', fontSize: '18px', color: '#333' }}>{song.title}</div>
                                <div style={{ fontSize: '14px', color: '#888' }}>{song.artist}</div>
                            </div>
                        </div>
                        <button onClick={() => playSong(index)} style={{ 
                            padding: '10px 30px', 
                            background: '#28a745', 
                            color: '#fff', 
                            border: 'none', 
                            borderRadius: '25px', 
                            cursor: 'pointer', 
                            fontWeight: 'bold' 
                        }}>
                            PLAY
                        </button>
                    </div>
                ))}
            </div>

            {/* Thanh Player cố định bên dưới */}
            {currentSong && (
                <div style={{
                    position: 'fixed', bottom: 0, left: 0, right: 0, 
                    background: '#111', color: '#fff', padding: '15px 50px', 
                    display: 'flex', alignItems: 'center', justifyContent: 'space-between', zIndex: 1000
                }}>
                    <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
                        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={{ width: '50px', height: '50px', borderRadius: '5px', marginRight: '15px' }} alt="playing" />
                        <div style={{ overflow: 'hidden' }}>
                            <div style={{ fontWeight: 'bold', fontSize: '14px', whiteSpace: 'nowrap', textOverflow: 'ellipsis' }}>{currentSong.title}</div>
                            <div style={{ fontSize: '12px', color: '#aaa' }}>{currentSong.artist}</div>
                        </div>
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '40%' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '30px' }}>
                            <button onClick={prevSong} style={iconBtnStyle}>⏮</button>
                            <button onClick={togglePlay} style={playBtnCircleStyle}>
                                {isPlaying ? '⏸' : '▶'}
                            </button>
                            <button onClick={nextSong} style={iconBtnStyle}>⏭</button>
                        </div>
                        <audio 
                            ref={audioRef}
                            src={`http://localhost:5000${currentSong.songUrl}`} 
                            autoPlay 
                            onEnded={nextSong}
                            onPlay={() => setIsPlaying(true)}
                            onPause={() => setIsPlaying(false)}
                        />
                    </div>

                    <div style={{ width: '30%', textAlign: 'right', fontSize: '12px', color: '#555' }}>
                        Music Player v1.0
                    </div>
                </div>
            )}
        </div>
    );
};

const iconBtnStyle = { background: 'none', border: 'none', color: '#fff', fontSize: '28px', cursor: 'pointer' };
const playBtnCircleStyle = { 
    background: '#fff', border: 'none', color: '#000', width: '45px', height: '45px', 
    borderRadius: '50%', fontSize: '20px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' 
};

export default Home;
